const currentDate = new Date();
const dayOfWeek = currentDate.getDay(); // 0 = Sunday, 1 = Monday, etc.
const hour = currentDate.getHours();

// Example: Only post on weekdays (Monday-Friday)
const isWeekday = dayOfWeek >= 1 && dayOfWeek <= 5;

// Get random motivational message
const messages = [
  "🌟 <b>Good morning!</b>\n\nStart your day with positive energy!\n\n<i>Today is {{ $now.format('dddd, MMMM D, YYYY') }}</i>",
  "☀️ <b>New day, new opportunities!</b>\n\nMake today count!\n\n<i>{{ $now.format('dddd, MMMM D, YYYY') }}</i>",
  "💪 <b>Rise and shine!</b>\n\nYou've got this!\n\n<i>{{ $now.format('dddd, MMMM D, YYYY') }}</i>",
  "🎯 <b>Focus on your goals!</b>\n\nEvery step forward counts.\n\n<i>{{ $now.format('dddd, MMMM D, YYYY') }}</i>",
  "✨ <b>Believe in yourself!</b>\n\nGreat things are coming your way.\n\n<i>{{ $now.format('dddd, MMMM D, YYYY') }}</i>"
];

const randomMessage = messages[Math.floor(Math.random() * messages.length)];

return {
  chatId: '-1001234567890', // Replace with your group chat ID
  message: randomMessage,
  shouldPost: isWeekday,
  timestamp: currentDate.toISOString(),
  dayOfWeek: dayOfWeek,
  hour: hour
};
